arguments.file_text:
@code {
    private int _step = 1;
    private readonly Order _order = new();

    [Parameter]
    public EventCallback<Order> OnOrderPlaced { get; set; }

    private void GoToPayment()
    {
        _step = 2;
    }

    private void GoBackToShipping()
    {
        _step = 1;
    }

    private async Task PlaceOrderAsync()
    {
        await OnOrderPlaced.InvokeAsync(_order);
    }
}

<div class="checkout-wizard">
    <h2>Checkout — Step @_step of 2</h2>

    @if (_step == 1)
    {
        <ShippingStep Shipping="_order.Shipping" OnNext="GoToPayment" />
    }
    else
    {
        <PaymentStep Payment="_order.Payment"
                     OnBack="GoBackToShipping"
                     OnPlaceOrder="PlaceOrderAsync" />
    }
</div>

@implements IDisposable
@inject IAddressValidator AddressValidator

@code {
    private CancellationTokenSource? _cts;
    private bool _isValidating;
    private string? _validationError;

    [Parameter, EditorRequired]
    public ShippingInfo Shipping { get; set; } = default!;

    [Parameter]
    public EventCallback OnNext { get; set; }

    private async Task ValidateAndProceedAsync()
    {
        // Cancel any in-flight validation.
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        _validationError = null;
        _isValidating = true;

        try
        {
            var isValid = await AddressValidator.ValidateAddressAsync(
                Shipping.Address, Shipping.City, Shipping.ZipCode, token);

            token.ThrowIfCancellationRequested();

            if (isValid)
            {
                await OnNext.InvokeAsync();
            }
            else
            {
                _validationError = "The address could not be verified. Please check your details.";
            }
        }
        catch (OperationCanceledException)
        {
            // Validation was superseded or component disposed — nothing to do.
        }
        finally
        {
            // Only clear the spinner if this is still the active validation.
            if (!token.IsCancellationRequested)
            {
                _isValidating = false;
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
    }
}

<fieldset disabled="@_isValidating">
    <div class="form-group">
        <label for="name">Name</label>
        <input id="name" @bind="Shipping.Name" @bind:event="oninput" />
    </div>

    <div class="form-group">
        <label for="address">Address</label>
        <input id="address" @bind="Shipping.Address" @bind:event="oninput" />
    </div>

    <div class="form-group">
        <label for="city">City</label>
        <input id="city" @bind="Shipping.City" @bind:event="oninput" />
    </div>

    <div class="form-group">
        <label for="zip">Zip Code</label>
        <input id="zip" @bind="Shipping.ZipCode" @bind:event="oninput" />
    </div>
</fieldset>

@if (_validationError is not null)
{
    <div class="validation-error" role="alert">@_validationError</div>
}

<button disabled="@_isValidating" @onclick="ValidateAndProceedAsync">
    @if (_isValidating)
    {
        <span class="spinner" aria-hidden="true"></span>
        <span>Validating…</span>
    }
    else
    {
        <span>Next</span>
    }
</button>

